#requires -Version 7.0
<#
.SYNOPSIS
  UDR Skills installer for Windows PowerShell 7+

.DESCRIPTION
  - 既存 udr-* / _udr-shared があれば .bak-<timestamp> に退避
  - skills を上書きコピー
  - target に .gitignore がなければ最小ファイルを生成
  - --Gemini: GEMINI.md と .gemini/extensions/udr/ を生成

.EXAMPLE
  pwsh dist\scripts\install.ps1 C:\path\to\target-project

.EXAMPLE
  pwsh dist\scripts\install.ps1 C:\path\to\target-project -Gemini -Codex

.EXAMPLE
  pwsh dist\scripts\install.ps1 -Global
#>

param(
  [Parameter(Position = 0)]
  [string]$TargetProject,

  [switch]$Global,
  [switch]$Gemini,
  [switch]$Codex
)

$ErrorActionPreference = 'Stop'

$ScriptDir = Split-Path -Parent $MyInvocation.MyCommand.Path
$DistRoot  = (Resolve-Path (Join-Path $ScriptDir '..')).Path
$RepoRoot  = (Resolve-Path (Join-Path $DistRoot '..')).Path
$Src       = Join-Path $RepoRoot '.claude\skills'

if (-not (Test-Path $Src -PathType Container)) {
  Write-Error "展開元 skills ディレクトリが見つかりません: $Src (.claude/skills が source of truth です)"
  exit 1
}

if (-not $Global -and -not $TargetProject) {
  Write-Error "Usage: install.ps1 <target-project-root> | -Global [-Gemini] [-Codex]"
  exit 2
}

$ts = (Get-Date -AsUTC).ToString('yyyyMMddTHHmmss')

if ($Global) {
  $TargetDir  = Join-Path $HOME '.claude\skills'
  $TargetRoot = $HOME
  $Scope      = "global (~\.claude\skills)"
} else {
  if (-not (Test-Path $TargetProject -PathType Container)) {
    Write-Error "対象ディレクトリが存在しません: $TargetProject"
    exit 3
  }
  $TargetDir  = Join-Path $TargetProject '.claude\skills'
  $TargetRoot = $TargetProject
  $Scope      = "project ($TargetProject)"
}

Write-Host ">> Installing UDR Skills"
Write-Host "   scope:  $Scope"
Write-Host "   target: $TargetDir"
if ($Gemini) { Write-Host "   + Gemini CLI セットアップ" }
if ($Codex)  { Write-Host "   + Codex CLI セットアップ案内" }
Write-Host ""

New-Item -ItemType Directory -Path $TargetDir -Force | Out-Null

# 既存の退避
$names = @('_udr-shared', 'udr-init', 'udr-record', 'udr-search', 'udr-sync', 'udr-trace', 'udr-review', 'udr-dashboard', 'README.md')
foreach ($n in $names) {
  $p = Join-Path $TargetDir $n
  if (Test-Path $p) {
    $bak = "$p.bak-$ts"
    Write-Host "   backup: $n -> $(Split-Path -Leaf $bak)"
    Move-Item -LiteralPath $p -Destination $bak -Force
  }
}

Write-Host ">> Copying skills..."
Copy-Item -Recurse -Force -Path (Join-Path $Src '*') -Destination $TargetDir
Write-Host "   done."
Write-Host ""

# .gitignore 更新 (プロジェクトローカルのみ)
if (-not $Global) {
  $gi   = Join-Path $TargetRoot '.gitignore'
  $rule = '.claude/skills/**/*.bak-*'
  if (-not (Test-Path $gi)) {
    @"
# Auto-generated by UDR install.ps1
$rule
.udr/index.json
.udr/audit.log*
udr_dashboard.html
"@ | Set-Content -Path $gi -Encoding utf8
    Write-Host ">> .gitignore を生成しました: $gi"
  } else {
    $content = Get-Content -Path $gi -Raw
    if ($content -notmatch [regex]::Escape($rule)) {
      Add-Content -Path $gi -Value "`n# UDR installer backup artifacts`n$rule`n.udr/index.json`n.udr/audit.log*`nudr_dashboard.html" -Encoding utf8
      Write-Host ">> .gitignore に UDR 除外ルールを追記しました"
    }
  }
}

# VERSION 記録
$versionFile = Join-Path $DistRoot 'VERSION'
if (Test-Path $versionFile) {
  Copy-Item -Path $versionFile -Destination (Join-Path $TargetDir '.udr-skills-version') -Force
}

$versionInfo = (Get-Content (Join-Path $TargetDir '.udr-skills-version') -ErrorAction SilentlyContinue | Select-Object -First 1)

# ── Gemini CLI セットアップ ──────────────────────────────────
if ($Gemini -and -not $Global) {
  Write-Host ">> Gemini CLI セットアップ..."

  # GEMINI.md を生成（存在しない場合のみ）
  # テンプレートは .claude\deploy\GEMINI.md（source of truth を直接参照）
  $geminiMd   = Join-Path $TargetRoot 'GEMINI.md'
  $geminiTmpl = Join-Path $RepoRoot '.claude\deploy\GEMINI.md'
  if (Test-Path $geminiMd) {
    Write-Host "   GEMINI.md は既に存在します（スキップ）: $geminiMd"
  } elseif (Test-Path $geminiTmpl) {
    Copy-Item -Path $geminiTmpl -Destination $geminiMd -Force
    Write-Host "   GEMINI.md を生成しました: $geminiMd"
  } else {
    Write-Host "   WARN: テンプレートが見つかりません: $geminiTmpl"
  }

  # .gemini/extensions/udr/
  # テンプレートは .claude\deploy\.gemini\（source of truth を直接参照）
  $extDir  = Join-Path $TargetRoot '.gemini\extensions\udr'
  $extTmpl = Join-Path $RepoRoot '.claude\deploy\.gemini\extensions\udr\gemini-extension.json'
  New-Item -ItemType Directory -Path $extDir -Force | Out-Null
  $extJson = Join-Path $extDir 'gemini-extension.json'
  if (Test-Path $extJson) {
    Write-Host "   .gemini/extensions/udr/gemini-extension.json は既に存在します（スキップ）"
  } elseif (Test-Path $extTmpl) {
    Copy-Item -Path $extTmpl -Destination $extJson -Force
    Write-Host "   .gemini/extensions/udr/gemini-extension.json を生成しました"
  } else {
    Write-Host "   WARN: テンプレートが見つかりません: $extTmpl"
  }
  Write-Host ""
}

# ── Codex CLI セットアップ案内 ────────────────────────────────
if ($Codex -and -not $Global) {
  Write-Host ">> Codex CLI セットアップ案内"
  Write-Host "   Codex CLI は AGENTS.md を会話開始時に自動で読みます。"
  Write-Host "   UDR ポリシーを AGENTS.md に追加するには:"
  Write-Host "     1. AGENTS.md が存在しない場合は作成します"
  Write-Host "     2. プロジェクト説明と UDR 自動検知ポリシーを記載します"
  Write-Host "   テンプレートは .claude/skills/_udr-shared/templates/codex-prompts/ を参照してください"
  Write-Host ""
}

Write-Host ""
Write-Host "=============================================="
Write-Host " UDR Skills 展開完了"
Write-Host "=============================================="
Write-Host ""
Write-Host " 次のステップ:"
Write-Host "   1. Claude Code で対象プロジェクトを開く"
Write-Host "   2. /udr-init を実行して .udr/ を初期化"
Write-Host "      ※ 使う AI ツール (claude / gemini / codex 等) を選択すること"
Write-Host "   3. /udr-record で最初の判断を記録"
Write-Host "   4. /udr-sync で CLAUDE.md / GEMINI.md / AGENTS.md 等に同期"
Write-Host ""
if ($Gemini -and -not $Global) {
  Write-Host " Gemini CLI でも使うには:"
  Write-Host "   - GEMINI.md が生成済み"
  Write-Host "   - .gemini/extensions/udr/ が生成済み"
  Write-Host "   - .udr/config.yaml の tools に gemini を追加"
  Write-Host ""
}
if ($versionInfo) { Write-Host " バージョン: $versionInfo" }
Write-Host " バックアップ (もしあれば): *.bak-$ts"
Write-Host ""
